39: func (c *LDAP) AuthenticateProxy(ctx context.Context, r *authn.Request, username string, _ map[string]string) (*authn.Identity, error) {
40: 	info, err := c.service.User(username)
41: 	if errors.Is(err, multildap.ErrDidNotFindUser) {
42: 		return c.disableUser(ctx, username)
43: 	}
44: 
45: 	if err != nil {
46: 		return nil, err
47: 	}
48: 
49: 	return c.identityFromLDAPInfo(r.OrgID, info), nil
50: }
51: 
52: func (c *LDAP) AuthenticatePassword(ctx context.Context, r *authn.Request, username, password string) (*authn.Identity, error) {
53: 	info, err := c.service.Login(&login.LoginUserQuery{
54: 		Username: username,
55: 		Password: password,
56: 	})
57: 
58: 	if errors.Is(err, multildap.ErrCouldNotFindUser) {
59: 		return c.disableUser(ctx, username)
60: 	}
61: 
62: 	// user was found so set auth module in req metadata
63: 	r.SetMeta(authn.MetaKeyAuthModule, "ldap")
64: 
65: 	if errors.Is(err, multildap.ErrInvalidCredentials) {
66: 		return nil, errInvalidPassword.Errorf("invalid password: %w", err)
67: 	}
68: 
69: 	if err != nil {
70: 		return nil, err
71: 	}
72: 
73: 	return c.identityFromLDAPInfo(r.OrgID, info), nil
74: }
