76: // disableUser will disable users if they logged in via LDAP previously
77: func (c *LDAP) disableUser(ctx context.Context, username string) (*authn.Identity, error) {
78: 	c.logger.Debug("User was not found in the LDAP directory tree", "username", username)
79: 	retErr := errIdentityNotFound.Errorf("no user found: %w", multildap.ErrDidNotFindUser)
80: 
81: 	// Retrieve the user from store based on the login
82: 	dbUser, errGet := c.userService.GetByLogin(ctx, &user.GetUserByLoginQuery{
83: 		LoginOrEmail: username,
84: 	})
85: 	if errors.Is(errGet, user.ErrUserNotFound) {
86: 		return nil, retErr
87: 	} else if errGet != nil {
88: 		return nil, errGet
89: 	}
90: 
91: 	// Check if the user logged in via LDAP
92: 	query := &login.GetAuthInfoQuery{UserId: dbUser.ID, AuthModule: login.LDAPAuthModule}
93: 	authinfo, errGetAuthInfo := c.authInfoService.GetAuthInfo(ctx, query)
94: 	if errors.Is(errGetAuthInfo, user.ErrUserNotFound) {
95: 		return nil, retErr
96: 	} else if errGetAuthInfo != nil {
97: 		return nil, errGetAuthInfo
98: 	}
99: 
100: 	// Disable the user
101: 	c.logger.Debug("User was removed from the LDAP directory tree, disabling it", "username", username, "authID", authinfo.AuthId)
102: 	isDiabled := true
103: 	if errDisable := c.userService.Update(ctx, &user.UpdateUserCommand{UserID: dbUser.ID, IsDisabled: &isDiabled}); errDisable != nil {
104: 		return nil, errDisable
105: 	}
106: 
107: 	return nil, retErr
108: }
