110: func (c *LDAP) identityFromLDAPInfo(orgID int64, info *login.ExternalUserInfo) *authn.Identity {
111: 	return &authn.Identity{
112: 		OrgID:           orgID,
113: 		OrgRoles:        info.OrgRoles,
114: 		Login:           info.Login,
115: 		Name:            info.Name,
116: 		Email:           info.Email,
117: 		IsGrafanaAdmin:  info.IsGrafanaAdmin,
118: 		AuthenticatedBy: info.AuthModule,
119: 		AuthID:          info.AuthId,
120: 		Groups:          info.Groups,
121: 		ClientParams: authn.ClientParams{
122: 			SyncUser:        true,
123: 			SyncTeams:       true,
124: 			EnableUser:      true,
125: 			FetchSyncedUser: true,
126: 			SyncPermissions: true,
127: 			SyncOrgRoles:    !c.cfg.LDAPSkipOrgRoleSync,
128: 			AllowSignUp:     c.cfg.LDAPAllowSignup,
129: 			LookUpParams: login.UserLookupParams{
130: 				Login: &info.Login,
131: 				Email: &info.Email,
132: 			},
133: 		},
134: 	}
135: }
